-- Verify total health courses
-- ============================================
SELECT '=== HEALTH COURSES IMPORT SUMMARY ===' as info;
SELECT COUNT(*) as total_health_courses FROM opportunities WHERE type = 'course' AND educational_field = 'ciencias_salud';
SELECT course_subject, COUNT(*) as count FROM opportunities WHERE type = 'course' AND educational_field = 'ciencias_salud' GROUP BY course_subject ORDER BY count DESC;
SELECT course_level, COUNT(*) as count FROM opportunities WHERE type = 'course' AND educational_field = 'ciencias_salud' GROUP BY course_level ORDER BY count DESC;
SELECT course_language, COUNT(*) as count FROM opportunities WHERE type = 'course' AND educational_field = 'ciencias_salud' GROUP BY course_language ORDER BY count DESC;





